        VistoParameter.Value.Should().Be(VistoValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBHorasTrabDicInfo.PTabelaNome}].[{DBHorasTrabDicInfo.Visto}] = @{DBHorasTrabDicInfo.Visto}");
    }

